def remove_duplicates(items):
result = []
seen = set()
for item in items:
    if item not in seen:
      result.append(item)
       seen.add(item)
return result

def fibonacci_sequence(limit):
sequence = [0, 1]
while True:
  next_number = sequence[-1] + sequence[-2]
     if next_number > limit:
       break
     sequence.append(next_number)
return sequence

