def is_balanced(expression):
stack = []
brackets = {'(': ')', '[': ']', '{': '}'}
for char in expression:
     if char in brackets:
      stack.append(char)
    elif char in brackets.values():
       if not stack or brackets[stack.pop()] != char:
    return False
return len(stack) == 0

